  KBTC: "BTC",
  BBTC: "BTC",
  SYBTC: "BTC",
  "WBTC.E": "BTC",

  // --- ETH derivatives ---
  STETH: "ETH",
  RETH: "ETH",
  WSTETH: "ETH",
